from typing import Optional
from .diff_engine import DiffResult, DiffType
from .adapters.base import BaseDBAdapter


class SQLGenerator:
    """SQL 同步语句生成器"""
    
    def __init__(self, adapter: BaseDBAdapter):
        self.adapter = adapter
    
    def generate_sync_sql(self, diffs: list[DiffResult]) -> str:
        """根据差异列表生成同步 SQL 语句
        
        Args:
            diffs: 差异结果列表（仅包含 selected=True 的项）
            
        Returns:
            完整的同步 SQL 脚本
        """
        sql_parts = []
        sql_parts.append("-- Database Structure Sync SQL")
        sql_parts.append("-- Generated by DB Diff Tool\n")
        
        # 收集新增表和删除表的表名
        new_tables = {}
        drop_tables = set()
        for diff in diffs:
            if diff.diff_type == DiffType.NEW_TABLE and diff.source_schema:
                new_tables[diff.table_name] = diff
            elif diff.diff_type == DiffType.DROP_TABLE:
                drop_tables.add(diff.table_name)
        
        # 检查新增表是否有选中的子项
        new_tables_with_selected_children = set()
        for diff in diffs:
            if diff.table_name in new_tables and diff.selected:
                if diff.diff_type in (DiffType.NEW_COLUMN, DiffType.NEW_INDEX, DiffType.NEW_FOREIGN_KEY):
                    new_tables_with_selected_children.add(diff.table_name)
        
        for diff in diffs:
            # 新增表处理：只要表本身或子项被选中，就生成 CREATE TABLE
            if diff.table_name in new_tables:
                table_diff = new_tables[diff.table_name]
                # 只在处理 NEW_TABLE 节点时生成 SQL（无论它是否被选中）
                if diff.diff_type == DiffType.NEW_TABLE:
                    # 检查是否有任何子项被选中或表本身被选中
                    has_selected = table_diff.selected or diff.table_name in new_tables_with_selected_children
                    if has_selected:
                        sql = self._generate_create_table_with_selected(diff, diffs)
                        if sql:
                            sql_parts.append(f"-- {diff.description}")
                            sql_parts.append(sql)
                            sql_parts.append("")
                # 跳过该表的所有子项（已合并到 CREATE TABLE 中）
                continue
            
            if not diff.selected:
                continue
            
            # 跳过删除表的子项（DROP TABLE 已处理整表）
            if diff.table_name in drop_tables and diff.diff_type in (
                DiffType.DROP_COLUMN, DiffType.DROP_INDEX, DiffType.DROP_FOREIGN_KEY
            ):
                continue
            
            sql = self._generate_sql_for_diff(diff)
            if sql:
                sql_parts.append(f"-- {diff.description}")
                sql_parts.append(sql)
                sql_parts.append("")
        
        if len(sql_parts) <= 2:
            return "-- No changes selected for sync."
        
        return "\n".join(sql_parts)
    
    def _generate_create_table_with_selected(self, table_diff: DiffResult, all_diffs: list[DiffResult]) -> Optional[str]:
        """为新增表动态生成 CREATE TABLE，只包含勾选的子项"""
        if not table_diff.source_schema:
            return f"-- 错误: 缺少表结构信息，无法生成 CREATE TABLE"
        
        table_name = table_diff.table_name
        
        # 收集该表下所有勾选的子项
        selected_columns = set()
        selected_indexes = set()
        selected_fks = set()
        
        for d in all_diffs:
            if d.table_name != table_name or not d.selected:
                continue
            if d.diff_type == DiffType.NEW_COLUMN:
                selected_columns.add(d.object_name)
            elif d.diff_type == DiffType.NEW_INDEX:
                selected_indexes.add(d.object_name)
            elif d.diff_type == DiffType.NEW_FOREIGN_KEY:
                selected_fks.add(d.object_name)
        
        # 过滤字段：只保留勾选的字段
        filtered_columns = [col for col in table_diff.source_schema.columns if col['name'] in selected_columns]
        
        # 过滤索引：只保留勾选的索引，且索引依赖的字段都被勾选
        filtered_indexes = []
        for idx in table_diff.source_schema.indexes:
            if idx['name'] in selected_indexes:
                # 检查索引依赖的字段是否都被勾选
                if all(c in selected_columns for c in idx['columns']):
                    filtered_indexes.append(idx)
        
        # 过滤外键：只保留勾选的外键，且外键依赖的字段都被勾选
        filtered_fks = []
        for fk in table_diff.source_schema.foreign_keys:
            if fk['name'] in selected_fks:
                # 检查外键依赖的字段是否都被勾选
                if all(c in selected_columns for c in fk['columns']):
                    filtered_fks.append(fk)
        
        return self.adapter.generate_create_table_sql(
            table=table_name,
            columns=filtered_columns,
            indexes=filtered_indexes,
            foreign_keys=filtered_fks,
            table_comment=table_diff.source_schema.comment
        )
    
    def _generate_sql_for_diff(self, diff: DiffResult) -> Optional[str]:
        """为单个差异项生成 SQL"""
        dt = diff.diff_type
        
        if dt == DiffType.NEW_TABLE:
            # 自动生成完整的 CREATE TABLE 语句
            if diff.source_schema:
                return self.adapter.generate_create_table_sql(
                    table=diff.table_name,
                    columns=diff.source_schema.columns,
                    indexes=diff.source_schema.indexes,
                    foreign_keys=diff.source_schema.foreign_keys,
                    table_comment=diff.source_schema.comment  # 传递表注释
                )
            return f"-- 错误: 缺少表结构信息，无法生成 CREATE TABLE"
        
        elif dt == DiffType.DROP_TABLE:
            # 生成删除表的 SQL（带注释说明原表结构）
            sql = f"DROP TABLE IF EXISTS {self._quote_table(diff.table_name)};"
            if diff.target_schema:
                # 添加注释说明被删除的表结构
                comment_lines = [f"-- 原表 {diff.table_name} 结构:"]
                for col in diff.target_schema.columns:
                    comment_lines.append(f"--   {col['name']} {col['type']}{' NOT NULL' if not col.get('nullable', True) else ''}")
                sql = "\n".join(comment_lines) + "\n" + sql
            return sql
        
        elif dt == DiffType.NEW_COLUMN:
            # 使用完整的字段信息
            if diff.source_column:
                return self.adapter.generate_add_column_sql(diff.table_name, diff.source_column)
            # 降级处理：使用基本信息
            return self.adapter.generate_add_column_sql(diff.table_name, {
                "name": diff.object_name,
                "type": diff.source_value or "VARCHAR(255)",
                "nullable": True,
                "default": None,
                "comment": "",
            })
        
        elif dt == DiffType.MODIFY_COLUMN:
            # 使用完整的字段信息
            if diff.source_column:
                return self.adapter.generate_modify_column_sql(diff.table_name, diff.target_column or {}, diff.source_column)
            # 降级处理：使用基本信息
            return self.adapter.generate_modify_column_sql(diff.table_name, {}, {
                "name": diff.object_name,
                "type": diff.source_value or "VARCHAR(255)",
                "comment": "",
            })
        
        elif dt == DiffType.DROP_COLUMN:
            return self.adapter.generate_drop_column_sql(diff.table_name, diff.object_name)
        
        elif dt == DiffType.NEW_INDEX:
            # 从 source_schema 中获取完整的索引信息
            if diff.source_schema:
                for idx in diff.source_schema.indexes:
                    if idx['name'] == diff.object_name:
                        return self.adapter.generate_add_index_sql(diff.table_name, idx)
            return f"-- 错误: 缺少索引信息"
        
        elif dt == DiffType.DROP_INDEX:
            return self.adapter.generate_drop_index_sql(diff.table_name, diff.object_name)
        
        elif dt == DiffType.NEW_FOREIGN_KEY:
            # 从 source_schema 中获取完整的外键信息
            if diff.source_schema:
                for fk in diff.source_schema.foreign_keys:
                    if fk['name'] == diff.object_name:
                        return self.adapter.generate_add_foreign_key_sql(diff.table_name, fk)
            return f"-- 错误: 缺少外键信息"
        
        elif dt == DiffType.MODIFY_FOREIGN_KEY:
            # 删除旧外键，添加新外键
            if diff.source_schema and diff.target_schema:
                old_fk = None
                new_fk = None
                for fk in diff.target_schema.foreign_keys:
                    if fk['name'] == diff.object_name:
                        old_fk = fk
                for fk in diff.source_schema.foreign_keys:
                    if fk['name'] == diff.object_name:
                        new_fk = fk
                if old_fk and new_fk:
                    sql = self.adapter.generate_drop_foreign_key_sql(diff.table_name, old_fk['name'])
                    sql += "\n"
                    sql += self.adapter.generate_add_foreign_key_sql(diff.table_name, new_fk)
                    return sql
            return f"-- 错误: 缺少外键信息"
        
        elif dt == DiffType.DROP_FOREIGN_KEY:
            return self.adapter.generate_drop_foreign_key_sql(diff.table_name, diff.object_name)
        
        # 视图处理
        elif dt == DiffType.NEW_VIEW:
            if diff.source_definition:
                return self.adapter.generate_create_view_sql({
                    "name": diff.object_name,
                    "definition": diff.source_definition
                })
            return f"-- 错误: 缺少视图定义"
        
        elif dt == DiffType.DROP_VIEW:
            return self.adapter.generate_drop_view_sql(diff.object_name)
        
        elif dt == DiffType.MODIFY_VIEW:
            if diff.source_definition:
                return self.adapter.generate_create_view_sql({
                    "name": diff.object_name,
                    "definition": diff.source_definition
                })
            return f"-- 错误: 缺少视图定义"
        
        # 存储过程处理
        elif dt == DiffType.NEW_PROCEDURE:
            if diff.source_definition:
                proc_type = "PROCEDURE"
                if diff.source_value and "FUNCTION" in diff.source_value.upper():
                    proc_type = "FUNCTION"
                return self.adapter.generate_create_procedure_sql({
                    "name": diff.object_name,
                    "definition": diff.source_definition,
                    "type": proc_type
                })
            return f"-- 错误: 缺少存储过程定义"
        
        elif dt == DiffType.DROP_PROCEDURE:
            proc_type = "PROCEDURE"
            if diff.target_value and "FUNCTION" in diff.target_value.upper():
                proc_type = "FUNCTION"
            return self.adapter.generate_drop_procedure_sql(diff.object_name, proc_type)
        
        elif dt == DiffType.MODIFY_PROCEDURE:
            if diff.source_definition:
                proc_type = "PROCEDURE"
                if diff.source_value and "FUNCTION" in diff.source_value.upper():
                    proc_type = "FUNCTION"
                return self.adapter.generate_create_procedure_sql({
                    "name": diff.object_name,
                    "definition": diff.source_definition,
                    "type": proc_type
                })
            return f"-- 错误: 缺少存储过程定义"
        
        # 触发器处理
        elif dt == DiffType.NEW_TRIGGER:
            if diff.source_definition:
                return self.adapter.generate_create_trigger_sql({
                    "name": diff.object_name,
                    "definition": diff.source_definition
                })
            return f"-- 错误: 缺少触发器定义"
        
        elif dt == DiffType.DROP_TRIGGER:
            return self.adapter.generate_drop_trigger_sql(diff.object_name)
        
        elif dt == DiffType.MODIFY_TRIGGER:
            if diff.source_definition:
                return self.adapter.generate_create_trigger_sql({
                    "name": diff.object_name,
                    "definition": diff.source_definition
                })
            return f"-- 错误: 缺少触发器定义"
        
        return None
    
    def _quote_table(self, name: str) -> str:
        """引用表名（适配不同数据库方言）"""
        if self.adapter.db_type == "mysql":
            return f"`{name}`"
        elif self.adapter.db_type == "postgresql":
            return f'"{name}"'
        return name
